import{_ as t,o as i,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt4201.jpg",l="/images/lekt4202.jpg",s="/images/lekt4203.jpg",u="/images/lekt4204.jpg",o="/images/lekt4208.jpg",p="/images/lekt4205.jpg",d="/images/lekt4206.jpg",m="/images/lekt4207.jpg",v=JSON.parse('{"title":"Lektion 42","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion42.md","filePath":"lektionen/lektion42.md"}'),h={name:"lektionen/lektion42.md"};function b(c,e,g,f,k,q){return i(),r("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-42" tabindex="-1">Lektion 42 <a class="header-anchor" href="#lektion-42" aria-label="Permalink to &quot;Lektion 42&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>42.1. Stämme auf -ṛ <ul><li>42.1.1. Stämme mit Dehnstufe im starken Stamm</li><li>42.1.2. Nominalbildung: कृत्-Suffix -तृ</li><li>42.1.3. Stämme mit Hochstufe im starken Stamm</li><li>42.1.4. Stämme auf -ṛ in Komposita</li></ul></li><li>42.2. Wortliste <ul><li>42.2.1. Einige Verwandtschaftsbezeichnungen</li></ul></li><li>42.3. Übung</li><li>42.4. Übersetzungsübung</li></ul><h2 id="_42-1-stamme-auf-r" tabindex="-1">42.1. Stämme auf -ṛ <a class="header-anchor" href="#_42-1-stamme-auf-r" aria-label="Permalink to &quot;42.1. Stämme auf -ṛ&quot;">​</a></h2><h3 id="_42-1-1-stamme-mit-dehnstufe-im-starken-stamm" tabindex="-1">42.1.1. Stämme mit Dehnstufe im starken Stamm <a class="header-anchor" href="#_42-1-1-stamme-mit-dehnstufe-im-starken-stamm" aria-label="Permalink to &quot;42.1.1. Stämme mit Dehnstufe im starken Stamm&quot;">​</a></h3><p>Alle Maskulina auf -ṛ mit Ausnahme der unter 1.3. angeführten Verwandtschaftsbezeichnungen. Hierher gehören auch die Verwandtschaftsbezeichnungen:</p><ul><li>नप्तृ m. &quot;Enkel&quot;</li><li>भर्तृ m. &quot;Gatte (wörtl. Erhalter)&quot;</li></ul><p>Den Großteil der hierhergehörigen Nomina bilden Nomina agentis auf das कृत्-Suffix -तृ.</p><p>Bildung:</p><ul><li>Starker Stamm: -ār</li><li>Schwacher Stamm <ul><li>vor Vokal: -r</li><li>vor Konsonant: -ṛ</li></ul></li></ul><p>Beachten Sie die unregelmäßigen Bildungen (durch rot gekennzeichnet)!</p><p>Maskulinum:</p><blockquote><p>दातृ m. &quot;Geber&quot;</p></blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>प्रथमा</td><td>दाता</td><td>दातारस्</td></tr><tr><td>द्वितीया</td><td>दातारम्</td><td>दातॄन्</td></tr><tr><td>तृतीया</td><td>दात्रा</td><td>दातृभिस्</td></tr><tr><td>चतुर्थी</td><td>दात्रे</td><td>दातृभ्यस्</td></tr><tr><td>पञ्चमी</td><td>दातुस्</td><td>दातृभ्यस्</td></tr><tr><td>षष्ठी</td><td>दातुस्</td><td>दातॄणाम्</td></tr><tr><td>सप्तमी</td><td>दातरि</td><td>दातृषु</td></tr></tbody></table><p>Zur Erklärung der unregelmäßigen Bildungen siehe Thumb-Hauschild I,2 S. 76 -81</p><p>Femininum:</p><blockquote><p>स्वसृ f. wird wie दातृ dekliniert mit Ausnahme des Akkusativ (द्वितीया) Plural: स्वसॄस्.</p></blockquote><h3 id="_42-1-2-nominalbildung-कृत्-suffix-तृ" tabindex="-1">42.1.2. Nominalbildung: कृत्-Suffix -तृ <a class="header-anchor" href="#_42-1-2-nominalbildung-कृत्-suffix-तृ" aria-label="Permalink to &quot;42.1.2. Nominalbildung: कृत्-Suffix -तृ&quot;">​</a></h3><p>Mit dem sehr häufig vorkommenden कृत्-Suffix -तृ bildet man Nomina agentis (Bezeichnungen für den कर्तृ) zu fast jeder Wurzel bzw. Kausativstamm.</p><p>Bildung:</p><ul><li>hochstufige Wurzel + -tṛ</li></ul><p>oder</p><ul><li>hochstufige Wurzel / Kausativstamm + i + tṛ</li></ul><p>Beispiele:</p><blockquote><p>कर्तृ m. &quot;Täter&quot;</p><p>जेतृ m. &quot;Sieger&quot;</p><p>धातृ m. &quot;Schöpfer&quot;</p><p>रक्षितृ m. &quot;Beschützer&quot;</p><p>बोधयितृ m. &quot;Wecker&quot;</p><p><img src="'+a+'" alt=""><br> Abb.: अयं बोधयिता<br> [Bildquelle: Wikipedia. Public domain]</p></blockquote><p>Selten vorkommende Neutra auf -तृ haben eine teilweise eigene Deklination (s. Kielhorn, Grammatik § 148.</p><p>Das Femininum zu den Stämmen auf -तृ lautet auf -त्री (wie देवी)</p><p>z.B. कर्त्री f. &quot;Täterin&quot;</p><h3 id="_42-1-3-stamme-mit-hochstufe-im-starken-stamm" tabindex="-1">42.1.3. Stämme mit Hochstufe im starken Stamm <a class="header-anchor" href="#_42-1-3-stamme-mit-hochstufe-im-starken-stamm" aria-label="Permalink to &quot;42.1.3. Stämme mit Hochstufe im starken Stamm&quot;">​</a></h3><p>Dazu gehören folgende Verwandtschaftsbezeichnungen:</p><ul><li>पितृ m. &quot;Vater&quot;</li><li>मातृ f. &quot;Mutter&quot;</li><li>दुहितृ f. &quot;Tochter&quot;</li><li>भ्रातृ m. &quot;Bruder&quot;</li><li>देवृ m. &quot;Gattenbruder (Schwager der Frau)&quot;</li><li>यातृ f. &quot;Frau des Gattenbruders&quot;</li><li>ननान्दृ f. &quot;Schwester des Gatten (Schwägerin der Frau)&quot;</li></ul><p>Bildung:</p><ul><li>starker Stamm: -ar</li><li>schwacher Stamm <ul><li>vor Vokal. -r</li><li>vor Konsonant: -ṛ</li></ul></li></ul><p>Beispiele:</p><blockquote><p>पितृ m. &quot;Vater&quot;</p><p>मातृ f. &quot;Mutter&quot;</p></blockquote><table tabindex="0"><thead><tr><th></th><th>पुंस्</th><th></th><th>स्त्री</th><th></th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>प्रथमा</td><td>पिता</td><td>पितरस्</td><td>माता</td><td>मातरस्</td></tr><tr><td>द्वितीया</td><td>पितरम्</td><td>पितॄन्</td><td>मातरम्</td><td>मातॄस्</td></tr><tr><td></td><td>Rest wie दातृ</td><td></td><td></td><td></td></tr></tbody></table><h3 id="_42-1-4-stamme-auf-r-in-komposita" tabindex="-1">42.1.4. Stämme auf -ṛ in Komposita <a class="header-anchor" href="#_42-1-4-stamme-auf-r-in-komposita" aria-label="Permalink to &quot;42.1.4. Stämme auf -ṛ in Komposita&quot;">​</a></h3><p>Als Vorderglied eines Kompositums stehen Nomina auf -ṛ selbstverständlich in ihrem schwachen Stamm, d.h.</p><ul><li>vor Konsonant: -ṛ</li><li>vor Vokal: -r</li></ul><h2 id="_42-2-wortliste" tabindex="-1">42.2. Wortliste <a class="header-anchor" href="#_42-2-wortliste" aria-label="Permalink to &quot;42.2. Wortliste&quot;">​</a></h2><p>प्रकृति f.: (zu कृ + प्र) Grundform, natürlicher Zustand, Natur; Urmaterie, Urstoff</p><p>अर्जुन m. Eigenname: Arjuna, einer der fünf Söhne des पण्डु. Held im महाभारत (siehe Basham, Wonder S. 409 - 414)</p><p>स्था + अव 1Ā अवतिष्ठते : abstehen von, Abstand nehmen von, sich fernhalten, verbleiben, dastehen</p><blockquote><p>PPP अवस्थित 3: dastehend, befindlich</p></blockquote><p>पुरा Adv.: einst, früher</p><p>अनेक 3: viele (nicht einige)</p><p>कुमार m.: Prinz</p><p>दूत m.: Bote, Gesandter</p><p>इष् (1,4,9) Kaus. इषयति : senden</p><p>सकाश m.: Anwesenheit, Gegenwart</p><p>शर m.: Pfeil-Schaft, Pfeil</p><p>बाण m.: Pfeil, Ziel</p><p>ज्ञा + प्रति 9U प्रतिजानाति : billigen, versprechen; Ā: antworten, bestätigen, behaupten, erkennen</p><p>चल् 1P चलति : in Bewegung geraten</p><blockquote><p>Fut. चलिष्यति<br> Perf. Vb चचाल, चेलुर्<br> Pass. चल्यते<br> Kaus. चलयति । चालयति<br> PPP चलित<br> Absol. -चल्य<br> Inf. चलितुम्</p></blockquote><p>अधिपति m. = राजन्</p><p>आटोप m.: Eitelkeit, Stolz</p><p>चिन्तापर 3: gedankenversunken</p><p>अन्तरे Adv.: inzwischen</p><p>लीला f.:  Scherz, Spiel</p><p>यावत् Adv.:  wie lange, während</p><p>तावत् Adv.: so lange</p><p>द्विधा । द्वेधा Adv.: zweifach, in zwei Teilen</p><p>शंस् 1P शंसति : loben, gebieten</p><blockquote><p>Fut. शंसिष्यति<br> Perf. I शशंस<br> Pass. शस्यते<br> Kaus. शंसयति<br> PPP शस्त<br> Absol. शसित्वा । शस्त्वा<br> Inf. शंसितुम्</p></blockquote><p>हृदय n.: Herz</p><h3 id="_42-2-1-einige-verwandtschaftsbezeichnungen" tabindex="-1">42.2.1. Einige Verwandtschaftsbezeichnungen <a class="header-anchor" href="#_42-2-1-einige-verwandtschaftsbezeichnungen" aria-label="Permalink to &quot;42.2.1. Einige Verwandtschaftsbezeichnungen&quot;">​</a></h3><p><img src="'+l+'" alt=""><br> Abb.: माता, पिता, पुत्रकः<br> The Diwan I Khas, or Hall of Private Audiences at the Lal Qila (Red Fort) in Delhi. <br> [Bildquelle: Wen-Yan King. -- <a href="http://www.flickr.com/photos/medapt/430287982/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/medapt/430287982/</a>. -- Zugriff am 2009-01-04. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>भर्तृ m. (zu भृ &quot;tragen, erhalten&quot;): Erhalter, Ernährer, Gatte</p><p>भार्या f.,  जाया f.  पत्नी f.: Gattin (भार्या = Gerundiv zu भृ : zu Tragende, zu Erhaltende, Unterhaltsberechtigte)</p><p>पितृ m.: Vater</p><p>पितृ m. Plural: die verstorbenen männlichen Vorfahren, d.h.</p><ol><li>Vater, Großvater, Urgroßvater</li><li>die Ahnväter der Menschheit</li></ol><p>Beiden werden Riten vollzogen, sog. श्राद्ध n. Täglich werden je drei männlichen  Vorfahren (väterlicherseits (und mütterlicherseits) Wasser und bei bestimmten Gelegenheiten Reisbällchen bzw. Mehlbällchen (पिण्ड m. &quot;Bällchen&quot;) dargebracht. So sollen die Vorfahren Nahrung bekommen. Der Vollzug dieser Zeremonie ist mit ein Grund, warum man als Mann einen Sohn zeugen soll. Diejenigen, die durch diese पिण्ड-Gabe verbunden sind heißen सपिण्ड (denen पिण्ड gemeinsam ist). सपिण्ड umfasst sechs Generationen: drei Rückwärts (bis zum Urgroßvater) und drei vorwärts (bis zum Großenkel).</p><p>तात m.: Papa</p><p>मातृ f.: Mutter</p><p>पुत्र m.:  Sohn</p><p>दुहितृ f. सुता f.: Tochter</p><p>नप्तृ m.: Enkel</p><p>भ्रातृ m.: Bruder</p><p>स्वसृ f., भगिनी f.: Schwester</p><p>देवृ m.: Bruder des Ehemanns (Schwager der Frau)</p><p>यातृ m.: Gattin des Bruders des Ehemanns</p><p>ननान्दृ f.: Schwester des Mannes</p><p>श्वसुर f.: Schwiegervater (in alter Zeit: nur der Frau)</p><p>श्वस्रू f.: Schwiegermutter (Deklination folgt später)</p><p>मातुल m.: Mutterbruder (Onkel mütterlicherseits)</p><p>मातुलानी f.: Gattin des Mutterbruders (Mutterbruderfrau)</p><p>पितृव्य m.: Vaterbruder (Onkel väterlicherseits)</p><p>पितामह m.: Großvater väterlicherseits</p><p>पितामही f.: Großmutter väterlicherseits</p><p>मातामह m.: Großvater mütterlicherseits</p><p>मातामही f.: Großmutter mütterlicherseits</p><h2 id="_42-3-ubung" tabindex="-1">42.3. Übung <a class="header-anchor" href="#_42-3-ubung" aria-label="Permalink to &quot;42.3. Übung&quot;">​</a></h2><p>Übersetzen Sie:</p><p>प्रकृत्यैव यः कर्माणि क्रियमाणानि पश्यति स आत्मानमकर्तरं पश्यति ॥१॥</p><p>कृष्णस्तस्य लोकस्य पिता माता पितामहो धातास्ति ॥२॥</p><p><img src="'+s+'" alt=""><br> Abb.: कृष्णस्तस्य लोकस्य पिता माता पितामहो धातास्ति<br> Tiruchchirappalli = தி௫ச்சிராப்பள்ளி, ca. 1825<br> [Bildquelle: Wikipedia. Public domain]</p><p>आचार्याः पितरः पुत्राश्च पितामहाः श्वशुरा नप्तरो युद्धायावस्थिताः । एतान्न हन्तुमिच्छामीत्यर्जुनो भगवद्गीतायामुवाच ॥३॥</p><p><img src="'+u+'" alt=""><br> Abb.: अर्जुनो रथे सीदति । कृष्णो ऽस्य रथवाहो ऽस्ति । (रथ m. Wagen)<br> [Bildquelle: Wikipedia. Public domain]</p><p>कवयो लब्धपुत्रतायाः पितॄन्मातॄश्च तुष्टुवुः ॥४॥</p><p>भर्त्रा भार्या भर्तव्या । तस्माद्भार्येत्युच्यते ॥५॥</p><p>सत्पुत्रः पितृभ्यः पिण्डान्ददाति । पितृभिः पिण्डदानमश्यत एवं च सुखजीवो जीवितुं शक्यते ॥६॥</p><p>भ्रात्रा स्वसा न विवोड्धव्या । भातरि स्वसारं कामयमाने देवाः क्रुध्यन्ति ॥७॥</p><p>क्थं भर्तुर्भ्रातोच्यते । देवेति भर्तुर्भ्राता वक्तव्यः ॥८॥</p><p>नप्तॄणां लाभं पितैच्छत् ॥९॥</p><h2 id="_42-4-ubersetzungsubung" tabindex="-1">42.4. Übersetzungsübung <a class="header-anchor" href="#_42-4-ubersetzungsubung" aria-label="Permalink to &quot;42.4. Übersetzungsübung&quot;">​</a></h2><p>सीताविवाहः</p><p>पुरा मिथिलायां जनको नाम राजा बभूव । तस्य सुता सीता नाम । सा रूपे शीले चानुपमा बभूव । तां परिणेतुमिछ्हन्तो ऽनेके राजकुमारा जनकाय दूतान्प्रेषयामासुः ॥</p><p>जनकस्तु तां वीर्यसम्पन्नाय क्षत्रियकुमाराय दातुमैच्छत् । अतः स तां वीर्येण क्रेतव्यामकल्पयत् । तथा हि -- तस्य सकाशे गुरुतरं किमपि धनुरासीत् । य इदं धनुरुद्धृत्यास्मिन्शरं सन्धत्ते स मम सुतां परिणेष्यतीति जनकः प्रतिजज्ञे ॥</p><p>तां तस्य प्रतिज्ञां श्रुत्वा शतशो राजकुमाराः समाजग्मुः । परं नैको ऽपि तेषां तद्धनुश्चलयितुमपि शशाक । लङ्काधिपती रावणो ऽपि साटोपं समेत्य सलज्जं प्रतिनिवृत्त इति ज्ञायते ॥</p><p>सर्वान्राजकुमारान्प्रतिवृत्तान्विलोक्य को मे दुहितुर्भर्ता भविष्यतीति चिन्तापरो बभूव जनकः । अत्रान्तरे ऽयोध्याधिपतेर्दशरथस्य पुत्रः श्रीरामः सलक्ष्मणो विश्वा्मित्रेण तत्रानीयत । श्रीरामो महर्षेर्विश्वामित्रस्य वचनेन लीलयैव तद्धनुरुद्धृत्य यावत्तस्मिन्बाणमारोपयति तावत्तद्धनुर्द्वेधा भग्नं बभूव ॥</p><p><img src="'+o+'" alt=""><br> Abb.: धनुर्द्वेधा भग्नं बभूव<br> Bild von राजा रवि वर्मा (1848 - 1906)<br> [Bildquelle: Wikipedia. Public domain]</p><p>साधु साध्विति श्रीरामस्य वीर्यं प्रशशंसुर्जनाः ॥</p><p>जनकस्य राज्ञो हृदयं प्रहृष्टं बभूव । ततः स दशरथादीनानाय्य महता विभवेन सीतरामयोर्विवाहोत्सवं निरवर्तयन् ॥</p><p>(संस्कृतप्रथमादर्शे)</p><p>Erklärung der rot hervorgehobenen Ausdrücke:</p><p>सीता f. Eigenname: Tochter des Königs जनक von विदेह. Sie war aus der Erde herausgekommen, als der König einst den Acker pflügte, deshalb ihr Name: सीता f. &quot;Ackerfurche&quot;</p><p><img src="'+p+'" alt=""><br> Abb.: रामः, सीता, हनुमान्, लक्ष्मनः<br> 17. Jhdt.<br> [Bildquelle. Wikipedia. Public domain]</p><p>मिथिला f. Eigenname: Hauptstadt von विदेह</p><p><img src="'+d+'" alt=""><br> Abb.: Lage von मिथिला und विदेह, अयोध्या und कोसल<br> [Bildquelle: JIJITH NR / Wikipedia. GNU FDLicense]</p><p>जनक m. Eigenname: König von विदेह</p><p>गुरुतर 3: Komparativ zu गुरु 3: schwerer, sehr schwer</p><p>धनुस् Nom.Akk.sg.n. zu धनुस् n. &quot;Bogen&quot;</p><p>शतशस् Adv.: zu hunderten</p><p>लङ्का f. Eigennamen: wird mit dem heutigen Sri Lanka (ශ්‍රී ලංකාව / இலங்கை) identifiziert</p><p>रावण m. Eigennamen; Herrscher von लङ्का, Herrscher der राक्षस.</p><p><img src="'+m+'" alt=""><br> Abb.: रावणः<br> Yakṣagaṇa-Tanzmaske (ಯಕ್ಷಗಾನ), Karnataka (ಕರ್ನಾಟಕ)<br> [Bildquelle: Manohara Upadhya / Wikipedia. GNU FDLicense]</p><p>अयोध्या f. Eigennamen: Hauptstadt von कोसल (siehe Karte oben!)</p><p>दशरथ m. Eigenname: König von कोसल</p><p>राम m. Eigenname: Sohn des दशरथ</p><p>लक्ष्मन m. Eigenname: Sohn des दशरथ</p><p>विश्वामित्र m. Eigenname: ऋषि, zog mir राम und लक्ष्मन aus, um Dämonen zu töten; dafür bekommen die beiden von ihm Zauberwaffen.</p><p>सीतारामयोस् Gen.Lok.Dual zu सीताराम</p>',135)])])}const w=t(h,[["render",b]]);export{v as __pageData,w as default};
